$ErrorActionPreference = 'Stop'  function Get-FrontmatterLines {     param([string]$Path)      $lines = Get-Content -Path $Path     if ($lines.Count -lt 3 -or $lines[0].Trim() -ne '---') {         return @()     }      $endIndex = -1     for ($i = 1; $i -lt $lines.Count; $i++) {         if ($lines[$i].Trim() -eq '---') {             $endIndex = $i             break         }     }      if ($endIndex -lt 1) {         return @()     }      return $lines[1..($endIndex - 1)] }  function Has-FrontmatterKey {     param(         [string[]]$Frontmatter,         [string]$Key     )      $pattern = '^' + [regex]::Escape($Key) + '\s*:'     return ($Frontmatter | Where-Object { $_ -match $pattern } | Measure-Object).Count -gt 0 }  function Get-AgentSlugFromPath {     param([string]$Path)     return [System.IO.Path]::GetFileName($Path) -replace '\.agent\.md$', '' }  $root = Resolve-Path (Join-Path $PSScriptRoot '..\..') $agentFiles = Get-ChildItem -Path (Join-Path $root '.github\agents') -Filter '*.agent.md' -File | Sort-Object Name $skillFiles = Get-ChildItem -Path (Join-Path $root '.github\skills') -Filter 'SKILL.md' -File -Recurse | Sort-Object FullName $registryPath = Join-Path $root '.github\AGENTS-REGISTRY.md'  $errors = New-Object System.Collections.Generic.List[string] $warnings = New-Object System.Collections.Generic.List[string]  $requiredBaseKeys = @('name', 'description', 'argument-hint') $requiredSkillSectionsStrict = @(     '## Summary',     '## When to use',     '## Expected input',     '## Blocking gates',     '## Workflow',     '## Output format' )  $requiredSkillSectionsAdvisory = @(     '## Constraints or rules',     '## References and related skills' )  foreach ($file in $agentFiles) {     $frontmatter = Get-FrontmatterLines -Path $file.FullName     if ($frontmatter.Count -eq 0) {         $errors.Add("$($file.FullName): missing YAML frontmatter")         continue     }      foreach ($key in $requiredBaseKeys) {         if (-not (Has-FrontmatterKey -Frontmatter $frontmatter -Key $key)) {             $errors.Add("$($file.FullName): missing required key '$key'")         }     }      if (-not (Has-FrontmatterKey -Frontmatter $frontmatter -Key 'user-invocable')) {         $errors.Add("$($file.FullName): missing required key 'user-invocable'")     } }  foreach ($file in $skillFiles) {     $frontmatter = Get-FrontmatterLines -Path $file.FullName     if ($frontmatter.Count -eq 0) {         $errors.Add("$($file.FullName): missing YAML frontmatter")         continue     }      foreach ($key in $requiredBaseKeys) {         if (-not (Has-FrontmatterKey -Frontmatter $frontmatter -Key $key)) {             $errors.Add("$($file.FullName): missing required key '$key'")         }     }      $content = Get-Content -Path $file.FullName     $lastIndex = -1     foreach ($section in $requiredSkillSectionsStrict) {         $index = [Array]::IndexOf($content, $section)         if ($index -lt 0) {             $warnings.Add("$($file.FullName): missing recommended section '$section'")             continue         }         if ($index -lt $lastIndex) {             $warnings.Add("$($file.FullName): recommended section order issue around '$section'")             continue         }         $lastIndex = $index     }      foreach ($section in $requiredSkillSectionsAdvisory) {         $index = [Array]::IndexOf($content, $section)         if ($index -lt 0) {             $warnings.Add("$($file.FullName): missing advisory section '$section' (recommended by schema)")             continue         }         if ($index -lt $lastIndex) {             $warnings.Add("$($file.FullName): advisory section order issue around '$section'")         }     } }  $registryContent = Get-Content -Path $registryPath -Raw foreach ($file in $agentFiles) {     $slug = Get-AgentSlugFromPath -Path $file.Name     $pattern = "\|\s*" + [regex]::Escape($slug) + "\s*\|"     if ($registryContent -notmatch $pattern) {         $errors.Add("${registryPath}: agent slug '$slug' is missing from Agents table")     } }  if ($warnings.Count -gt 0) {     Write-Host 'Warnings:' -ForegroundColor Yellow     $warnings | ForEach-Object { Write-Host "- $_" -ForegroundColor Yellow } }  if ($errors.Count -gt 0) {     Write-Host 'Validation failed:' -ForegroundColor Red     $errors | ForEach-Object { Write-Host "- $_" -ForegroundColor Red }     exit 1 }  Write-Host 'Validation passed: agent and skill definitions are synchronized.' -ForegroundColor Green